        let suspiciousSchemes = ["cydia://", "sileo://", "zbra://", "filza://", "activator://"]
        for scheme in suspiciousSchemes {
            if let url = URL(string: scheme), UIApplication.shared.canOpenURL(url) {
                return true
            }
        }
        
        // Check for dyld environment variables
        if let _ = getenv("DYLD_INSERT_LIBRARIES") {
            return true
        }
        
        // Check system calls
        var statInfo = stat()
        if stat("/Applications", &statInfo) == 0 {
            return true
        }
        
        // Fork check (jailbroken devices allow fork)
        let pid = fork()
        if pid >= 0 {
            if pid > 0 {
                kill(pid, SIGTERM)
            }
            return true
        }
        
        return false
    }
    
    private func detectDebugger() -> Bool {
        var info = kinfo_proc()
        var mib: [Int32] = [CTL_KERN, KERN_PROC, KERN_PROC_PID, getpid()]
        var size = MemoryLayout<kinfo_proc>.stride
        
        let result = sysctl(&mib, UInt32(mib.count), &info, &size, nil, 0)
        
        if result != 0 {
            return false
        }
        
        return (info.kp_proc.p_flag & P_TRACED) != 0
    }
    
    private func detectTampering() -> Bool {
        // Check code signature
        guard let executablePath = Bundle.main.executablePath else {
            return true
        }
        
        // Verify bundle integrity
        let originalHash = calculateBundleHash()
        if !verifyBundleHash(originalHash) {
            return true
        }
        
        // Check for suspicious frameworks
        let imageCount = _dyld_image_count()
        for i in 0..<imageCount {
            if let imageName = _dyld_get_image_name(i) {
                let name = String(cString: imageName).lowercased()
                if name.contains("substrate") || name.contains("cycript") || 
                   name.contains("frida") || name.contains("inject") {
                    return true
                }
            }
        }
        
        return false
    }
    
    private func detectHooking() -> Bool {
        // Check for method swizzling indicators
        let suspiciousMethods = [
            "URLSession",
            "NSURLConnection",
            "CFNetwork"
        ]
        
        // Additional runtime checks
        var info = Dl_info()
        if dladdr(dlsym(RTLD_DEFAULT, "URLSession"), &info) != 0 {
            if let dli_fname = info.dli_fname {
                let path = String(cString: dli_fname)
                if !path.contains("/System/Library/") {
                    return true
                }
            }
        }
        
        return false
    }
    
    private func calculateBundleHash() -> String {
        guard let bundlePath = Bundle.main.bundlePath as NSString? else {
            return ""
        }
        
        var hash = ""
        let fileManager = FileManager.default
        
        if let enumerator = fileManager.enumerator(atPath: bundlePath as String) {
            while let file = enumerator.nextObject() as? String {
                let filePath = bundlePath.appendingPathComponent(file)
                if let data = fileManager.contents(atPath: filePath) {
                    hash += data.sha256()
                }
            }
        }
        
        return hash
    }
    
    private func verifyBundleHash(_ hash: String) -> Bool {
        // In production, compare with stored hash from secure server
        return !hash.isEmpty
    }
}

struct DeviceSecurityStatus {
    let isJailbroken: Bool
    let isDebuggerAttached: Bool
    let isTampered: Bool
    let isHooked: Bool
    
    var isDeviceCompromised: Bool {
        return isJailbroken || isDebuggerAttached || isTampered || isHooked
    }
    
    var riskLevel: SecurityRiskLevel {
        if isDebuggerAttached || isTampered {
            return .critical
        } else if isJailbroken || isHooked {
            return .high
        } else {
            return .normal
        }
    }
}

enum SecurityRiskLevel {
    case normal
    case high
    case critical
}

