// MARK: - Secure Transaction Manager

class SecureTransactionManager {
    
    static let shared = SecureTransactionManager()
    
    private let encryptionService = EncryptionService.shared
    private let integrityChecker = DeviceIntegrityChecker.shared
    private let biometricAuth = BiometricAuthService.shared
    
    private var accounts: [Account] = []
    private var transactions: [Transaction] = []
    
    private init() {
        loadSecureData()
    }
    
    func processTransaction(_ transaction: Transaction, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        // Defense-in-depth: Check device integrity before processing sensitive operations
        let securityStatus = integrityChecker.performComprehensiveSecurityCheck()
        
        guard !securityStatus.isDeviceCompromised else {
            // Device is compromised - require additional security measures
            handleCompromisedDeviceTransaction(transaction, securityStatus: securityStatus, completion: completion)
            return
        }
        
        // Normal flow for trusted devices
        processTransactionSecurely(transaction, completion: completion)
    }
    
    private func handleCompromisedDeviceTransaction(_ transaction: Transaction, securityStatus: DeviceSecurityStatus, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        // Defense-in-depth: Gate sensitive features behind additional protections
        
        switch securityStatus.riskLevel {
        case .critical:
            // Block all transactions on critically compromised devices
            completion(.failure(.deviceCompromised("Critical security risk detected. Transactions are disabled for your safety.")))
            return
            
        case .high:
            // Require additional authentication for high-risk devices
            requireEnhancedAuthentication(for: transaction) { [weak self] authenticated in
                guard authenticated else {
                    completion(.failure(.authenticationFailed("Enhanced authentication required on this device")))
                    return
                }
                
                // Limit transaction amounts on compromised devices
                if transaction.amount > 100 {
                    completion(.failure(.transactionLimitExceeded("Transaction limit reduced due to security concerns. Please contact support.")))
                    return
                }
                
                self?.processTransactionSecurely(transaction, completion: completion)
            }
            
        case .normal:
            processTransactionSecurely(transaction, completion: completion)
        }
    }
    
    private func requireEnhancedAuthentication(for transaction: Transaction, completion: @escaping (Bool) -> Void) {
        // Require biometric authentication
        biometricAuth.authenticateUser(reason: "Authenticate to process transaction of \(transaction.amount) \(transaction.currency)") { success, error in
            if success {
                // Additional verification: require server-side verification token
                self.requestServerVerification(for: transaction) { verified in
                    completion(verified)
                }
            } else {
                completion(false)
            }
        }
    }
    
    private func requestServerVerification(for transaction: Transaction, completion: @escaping (Bool) -> Void) {
        // In production: Make secure API call to server for additional verification
        // For now, simulate server verification
        DispatchQueue.global().asyncAfter(deadline: .now() + 1.0) {
            completion(true)
        }
    }
    
    private func processTransactionSecurely(_ transaction: Transaction, completion: @escaping (Result<Transaction, TransactionError>) -> Void) {
        // Validate transaction
        guard validateTransaction(transaction) else {
            completion(.failure(.invalidTransaction))
            return
        }
        
        // Check sufficient balance
        guard let fromAccount = accounts.first(where: { $0.accountNumber == transaction.fromAccount }) else {
            completion(.failure(.accountNotFound))
            return
        }
        
        guard fromAccount.balance >= transaction.amount else {
            completion(.failure(.insufficientFunds))
            return
        }
        
        // Process transaction
        var updatedTransaction = transaction
        updatedTransaction = Transaction(
            id: transaction.id,
            fromAccount: transaction.fromAccount,
            toAccount: transaction.toAccount,
            amount: transaction.amount,
            currency: transaction.currency,
            timestamp: transaction.timestamp,
            description: transaction.description,
            status: .completed
        )
        
        // Update balances
        updateAccountBalance(accountNumber: transaction.fromAccount, amount: -transaction.amount)
        updateAccountBalance(accountNumber: transaction.toAccount, amount: transaction.amount)
        
        // Store transaction
        transactions.append(updatedTransaction)
        saveSecureData()
        
        completion(.success(updatedTransaction))
    }
    
    private func validateTransaction(_ transaction: Transaction) -> Bool {
        guard !transaction.fromAccount.isEmpty,
              !transaction.toAccount.isEmpty,
              transaction.amount > 0,
              transaction.fromAccount != transaction.toAccount else {
            return false
        }
        return true
    }
    
    private func updateAccountBalance(accountNumber: String, amount: Decimal) {
        if let index = accounts.firstIndex(where: { $0.accountNumber == accountNumber }) {
            var account = accounts[index]
            account.balance += amount
            accounts[index] = account
        }
    }
    
    func getAccountBalance(accountNumber: String) -> Decimal? {
        // Check device integrity before displaying sensitive information
        let securityStatus = integrityChecker.performComprehensiveSecurityCheck()
        
        guard !securityStatus.isDeviceCompromised else {
            // On compromised devices, require authentication before showing balance
            return nil
        }
        
        return accounts.first(where: { $0.accountNumber == accountNumber })?.balance
    }
    
    func getSecureAccountBalance(accountNumber: String, completion: @escaping (Result<Decimal, TransactionError>) -> Void) {
        let securityStatus = integrityChecker.performComprehensiveSecurityCheck()
        
        if securityStatus.isDeviceCompromised {
            // Require biometric authentication on compromised devices
            biometricAuth.authenticateUser(reason: "Authenticate to view account balance") { [weak self] success, error in
                guard success else {
                    completion(.failure(.authenticationFailed("Authentication required to view balance on this device")))
                    return
                }
                
                if let balance = self?.accounts.first(where: { $0.accountNumber == accountNumber })?.balance {
                    completion(.success(balance))
                } else {
                    completion(.failure(.accountNotFound))
                }
            }
        } else {
            if let balance = accounts.first(where: { $0.accountNumber == accountNumber })?.balance {
                completion(.success(balance))
            } else {
                completion(.failure(.accountNotFound))
            }
        }
    }
    
    func getAllAccounts() -> [Account] {
        let securityStatus = integrityChecker.performComprehensiveSecurityCheck()
        
        // On compromised devices, return limited information
        if securityStatus.isDeviceCompromised {
            return accounts.map { account in
                Account(
                    accountNumber: String(account.accountNumber.suffix(4)),
                    accountType: account.accountType,
                    balance: 0,
                    currency: account.currency
                )
            }
        }
        
        return accounts
    }
    
    func getTransactionHistory(accountNumber: String) -> [Transaction] {
        let securityStatus = integrityChecker.performComprehensiveSecurityCheck()
        
        // Limit transaction history on compromised devices
        let filtered = transactions.filter {
            $0.fromAccount == accountNumber || $0.toAccount == accountNumber
        }
        
        if securityStatus.isDeviceCompromised {
            return Array(filtered.prefix(5))
        }
        
        return filtered
    }
    
    private func saveSecureData() {
        let encoder = JSONEncoder()
        
        do {
            let accountsData = try encoder.encode(accounts)
            let transactionsData = try encoder.encode(transactions)
            
            let encryptedAccounts = try encryptionService.encryptData(accountsData)
            let encryptedTransactions = try encryptionService.encryptData(transactionsData)
            
            UserDefaults.standard.set(encryptedAccounts, forKey: "encrypted_accounts")
            UserDefaults.standard.set(encryptedTransactions, forKey: "encrypted_transactions")
        } catch {
            print("Failed to save secure data: \(error)")
        }
    }
    
    private func loadSecureData() {
        let decoder = JSONDecoder()
        
        do {
            if let encryptedAccounts = UserDefaults.standard.data(forKey: "encrypted_accounts") {
                let decryptedAccounts = try encryptionService.decryptData(encryptedAccounts)
                accounts = try decoder.decode([Account].self, from: decryptedAccounts)
            } else {
                // Initialize with sample accounts
                accounts = [
                    Account(accountNumber: "1234567890", accountType: .checking, balance: 5000.00, currency: "USD"),
                    Account(accountNumber: "0987654321", accountType: .savings, balance: 10000.00, currency: "USD")
                ]
            }
            
            if let encryptedTransactions = UserDefaults.standard.data(forKey: "encrypted_transactions") {
                let decryptedTransactions = try encryptionService.decryptData(encryptedTransactions)
                transactions = try decoder.decode([Transaction].self, from: decryptedTransactions)
            }
        } catch {
            print("Failed to load secure data: \(error)")
            accounts = []
            transactions = []
        }
    }
}

enum TransactionError: Error {
    case invalidTransaction
    case accountNotFound
    case insufficientFunds
    case deviceCompromised(String)
    case authenticationFailed(String)
    case transactionLimitExceeded(String)
}

