        var warningMessage = "⚠️ Security Warning: "
        
        if status.riskLevel == .critical {
            warningMessage += "Critical security risk detected. Some features are disabled."
            transferButton.isEnabled = false
            transferButton.backgroundColor = .systemGray
        } else {
            warningMessage += "Device integrity check failed. Enhanced security measures active."
        }
        
        securityWarningLabel.text = warningMessage
        securityWarningLabel.isHidden = false
    }
    
    private func loadAccountData() {
        let accounts = transactionManager.getAllAccounts()
        guard let account = accounts.first else { return }
        
        currentAccount = account
        accountLabel.text = "Account: ****\(account.accountNumber.suffix(4))"
        
        transactionManager.getSecureAccountBalance(accountNumber: account.accountNumber) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let balance):
                    self?.balanceLabel.text = "$\(balance)"
                case .failure(let error):
                    self?.balanceLabel.text = "****"
                    self?.showAlert(title: "Error", message: error.localizedDescription)
                }
            }
        }
        
        transactions = transactionManager.getTransactionHistory(accountNumber: account.accountNumber)
        transactionTableView.reloadData()
    }
    
    @objc private func transferTapped() {
        guard let currentAccount = currentAccount,
              let amountText = amountTextField.text,
              let amount = Decimal(string: amountText),
              let recipient = recipientTextField.text, !recipient.isEmpty else {
            showAlert(title: "Error", message: "Please enter valid amount and recipient")
            return
        }
        
        let transaction = Transaction(
            id: UUID().uuidString,
            fromAccount: currentAccount.accountNumber,
            toAccount: recipient,
            amount: amount,
            currency: "USD",
            timestamp: Date(),
            description: "Transfer",
            status: .pending
        )
        
        transactionManager.processTransaction(transaction) { [weak self] result in
            DispatchQueue.main.async {
                switch result {
                case .success(let completedTransaction):
                    self?.showAlert(title: "Success", message: "Transaction completed successfully")
                    self?.amountTextField.text = ""
                    self?.recipientTextField.text = ""
                    self?.loadAccountData()
                    
                case .failure(let error):
                    var message = "Transaction failed"
                    switch error {
                    case .deviceCompromised(let msg),
                         .authenticationFailed(let msg),
                         .transactionLimitExceeded(let msg):
                        message = msg
                    default:
                        message = error.localizedDescription
                    }
                    self?.showAlert(title: "Error", message: message)
                }
            }
        }
    }
    
    private func showAlert(title: String, message: String) {
        let alert = UIAlertController(title: title, message: message, preferredStyle: .alert)
        alert.addAction(UIAlertAction(title: "OK", style: .default))
        present(alert, animated: true)
    }
}

extension BankingViewController: UITableViewDelegate, UITableViewDataSource {
    func tableView(_ tableView: UITableView, numberOfRowsInSection section: Int) -> Int {
        return transactions.count
    }
    
    func tableView(_ tableView: UITableView, cellForRowAt indexPath: IndexPath) -> UITableViewCell {
        let cell = tableView.dequeueReusableCell(withIdentifier: "TransactionCell", for: indexPath)
        let transaction = transactions[indexPath.row]
        
        let isOutgoing = transaction.fromAccount == currentAccount?.accountNumber
        let sign = isOutgoing ? "-" : "+"
        
        cell.textLabel?.text = "\(sign)$\(transaction.amount) - \(transaction.description)"
        cell.detailTextLabel?.text = transaction.status.rawValue
        
        return cell
    }
}

// MARK: - Data Extensions

extension Data {
    func sha256() -> String {
        var hash = [UInt8](repeating: 0, count: Int(CC_SHA256_DIGEST_LENGTH))
        self.withUnsafeBytes {
            _ = CC_SHA256($0.baseAddress, CC_LONG(self.count), &hash)
        }
        return hash.map { String(format: "%02x", $0) }.joined()
    }
}